using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;

namespace WebhookProxy
{
    public class WebhookService
    {
        private readonly Dictionary<string, Uri> _webhooks;
        private readonly HttpClient _httpClient;
        private readonly ILogger<WebhookService> _logger;

        public WebhookService(HttpClient httpClient, ILogger<WebhookService> logger)
        {
            _webhooks = new Dictionary<string, Uri>();
            _httpClient = httpClient;
            _logger = logger;
        }

        public void AddWebhook(string id, Uri url)
        {
            if (_webhooks.ContainsKey(id)) throw new ArgumentException("Webhook ID already exists.");

            _webhooks[id] = url;
            _logger.LogInformation($"Added webhook '{id}' to URL: {url}");
        }

        public async Task ProcessRequestAsync(HttpContext context)
        {
            if (!_webhooks.TryGetValue(context.Request.Query["id"], out var uri))
            {
                context.Response.ContentType = "application/json";
                await context.Response.WriteAsJsonAsync(new { error = "Invalid or non-existent webhook ID." });
                return;
            }

            try
            {
                var response = await _httpClient.GetAsync(uri);
                response.EnsureSuccessStatusCode();

                var content = await response.Content.ReadAsStringAsync();
                context.Response.ContentType = response.Content.Headers.ContentType.MediaType;
                await context.Response.WriteAsync(content);
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError($"Failed to forward request for webhook '{context.Request.Query["id"]}': {ex}");
                context.Response.ContentType = "application/json";
                await context.Response.WriteAsJsonAsync(new { error = ex.Message });
            }
        }
    }
